     * Calculates the number of "good" integers in the range [l, r] based on the given directions.
     * A "good" integer is one where the sequence of digits visited along the path is non-decreasing.
     *
     * @param l The lower bound of the range (inclusive).
     * @param r The upper bound of the range (inclusive).
     * @param directions A string of 6 characters containing three 'D's and three 'R's.
     * @return The count of good integers in [l, r].
     */
    public long solve(long l, long r, String directions) {
        long count = 0;
        for (long x = l; x <= r; x++) {
            if (isGoodInteger(x, directions)) {
                count++;
            }
        }
        return count;
    }

    /**
     * Checks if a given integer x is a "good" integer according to the rules.
     */
    private boolean isGoodInteger(long x, String directions) {
        // 1. Format x as a 16-digit string with leading zeros
        String s = String.valueOf(x);
        String paddedS = String.format("%16s", s).replace(' ', '0');

        // 2. Place digits into a 4x4 grid
