        // 3. Traverse the grid and record the sequence
        int row = 0;
        int col = 0;
        // The sequence must include the starting cell (0,0) plus 6 moves -> total length 7
        int[] sequence = new int[7];
        sequence[0] = grid[row][col];

        // Apply 6 directions
        for (int i = 0; i < 6; i++) {
            char dir = directions.charAt(i);

            if (dir == 'D') {
                row++;
            } else if (dir == 'R') {
                col++;
            }

            // Note: The problem constraints imply the path stays within bounds for 6 moves, 
